package ua.university.sms.model.entity;
import jakarta.persistence.*;import java.util.*;
@Entity @Table(name="students") public class Student{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;@Column(name="full_name",nullable=false,length=200) private String fullName;@Column(nullable=false,unique=true) private String email;@Column(nullable=false) private int year;@Enumerated(EnumType.STRING) @Column(nullable=false) private StudentStatus status=StudentStatus.ACTIVE;@OneToMany(mappedBy="student",cascade=CascadeType.REMOVE) private List<Enrollment> enrollments=new ArrayList<>(); public Long getId(){return id;}public void setId(Long id){this.id=id;}public String getFullName(){return fullName;}public void setFullName(String fullName){this.fullName=fullName;}public String getEmail(){return email;}public void setEmail(String email){this.email=email;}public int getYear(){return year;}public void setYear(int year){this.year=year;}public StudentStatus getStatus(){return status;}public void setStatus(StudentStatus status){this.status=status;}public List<Enrollment> getEnrollments(){return enrollments;}}
